BEGIN;
CREATE TABLE IF NOT EXISTS arb.shipping_quote_batches(id bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,request_uuid uuid NOT NULL UNIQUE,decision_uuid uuid,quote_purpose text NOT NULL CHECK(quote_purpose IN('ZONE_ANCHOR','ACTUAL_DESTINATION')),origin_postal_code text NOT NULL,destination_postal_code text NOT NULL,anchor_key text,package_fingerprint text,source_system text NOT NULL,source_account text,complete boolean NOT NULL,source_latency_ms integer,failures_json jsonb NOT NULL DEFAULT '[]'::jsonb CHECK(jsonb_typeof(failures_json)='array'),requested_at timestamptz NOT NULL,completed_at timestamptz NOT NULL,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS arb.shipping_quote_items(id bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,quote_batch_id bigint NOT NULL REFERENCES arb.shipping_quote_batches(id) ON DELETE CASCADE,quote_external_id text NOT NULL,carrier_code text NOT NULL,service_code text NOT NULL,service_name text NOT NULL,total_charge_cents bigint NOT NULL CHECK(total_charge_cents>=0),currency text NOT NULL DEFAULT 'USD',commitment_type text NOT NULL CHECK(commitment_type IN('GUARANTEED','ESTIMATED','UNKNOWN')),estimated_delivery_business_days integer,quoted_at timestamptz NOT NULL,valid_until timestamptz,capabilities_json jsonb NOT NULL CHECK(jsonb_typeof(capabilities_json)='object'),insurance_mechanisms_json jsonb NOT NULL DEFAULT '[]'::jsonb CHECK(jsonb_typeof(insurance_mechanisms_json)='array'),tracking_quality_score numeric CHECK(tracking_quality_score BETWEEN 0 AND 100),on_time_probability numeric CHECK(on_time_probability BETWEEN 0 AND 1),raw_payload jsonb NOT NULL DEFAULT '{}'::jsonb,UNIQUE(quote_batch_id,quote_external_id));
CREATE TABLE IF NOT EXISTS arb.shipping_decision_versions(id bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,decision_uuid uuid NOT NULL,version_no integer NOT NULL,stage text NOT NULL,supersedes_decision_uuid uuid,policy_version text NOT NULL,ruleset_version text NOT NULL,model_version text NOT NULL,input_hash text NOT NULL CHECK(input_hash~'^[0-9a-f]{64}$'),evidence_hash text NOT NULL CHECK(evidence_hash~'^[0-9a-f]{64}$'),decision_json jsonb NOT NULL CHECK(jsonb_typeof(decision_json)='object'),created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(decision_uuid,version_no));
CREATE TABLE IF NOT EXISTS arb.shipping_prediction_history(id bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,decision_uuid uuid NOT NULL,shipment_id bigint NOT NULL REFERENCES arb.shipments(id),prediction_json jsonb NOT NULL CHECK(jsonb_typeof(prediction_json)='object'),created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(decision_uuid,shipment_id));
CREATE TABLE IF NOT EXISTS arb.shipping_outcomes(id bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,shipment_id bigint NOT NULL UNIQUE REFERENCES arb.shipments(id),outcome_json jsonb NOT NULL CHECK(jsonb_typeof(outcome_json)='object'),reconciled_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS arb.shipping_model_metrics(id bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,model_version text NOT NULL,metric_date date NOT NULL,metric_name text NOT NULL,segment_key text NOT NULL DEFAULT 'GLOBAL',metric_value numeric NOT NULL,sample_size integer NOT NULL DEFAULT 0,metric_json jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(model_version,metric_date,metric_name,segment_key));
CREATE TABLE IF NOT EXISTS arb.shipping_feature_vectors(id bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,decision_uuid uuid NOT NULL,feature_group text NOT NULL,features_json jsonb NOT NULL CHECK(jsonb_typeof(features_json)='object'),created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(decision_uuid,feature_group));
CREATE TABLE IF NOT EXISTS arb.shipping_confidence_history(id bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,decision_uuid uuid NOT NULL,confidence_type text NOT NULL,confidence_score numeric NOT NULL CHECK(confidence_score BETWEEN 0 AND 100),components_json jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS arb.shipping_digital_twins(id bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,twin_uuid uuid NOT NULL UNIQUE,sku text NOT NULL UNIQUE,category_key text,sample_size integer NOT NULL DEFAULT 0,confidence_score numeric NOT NULL DEFAULT 0 CHECK(confidence_score BETWEEN 0 AND 100),twin_json jsonb NOT NULL CHECK(jsonb_typeof(twin_json)='object'),last_verified_at timestamptz,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS arb.shipping_policy_simulations(id bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,simulation_uuid uuid NOT NULL UNIQUE,source_policy_version text NOT NULL,candidate_policy_version text NOT NULL,status text NOT NULL CHECK(status IN('QUEUED','RUNNING','SUCCEEDED','FAILED','CANCELLED')),source_window_start timestamptz,source_window_end timestamptz,result_json jsonb NOT NULL DEFAULT '{}'::jsonb,requested_by text,created_at timestamptz NOT NULL DEFAULT now(),completed_at timestamptz);
CREATE TABLE IF NOT EXISTS arb.shipping_model_drift_events(id bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,model_version text NOT NULL,drift_score numeric NOT NULL CHECK(drift_score BETWEEN 0 AND 100),drift_status text NOT NULL CHECK(drift_status IN('STABLE','WATCH','RECALIBRATE','DISABLE_MODEL')),observations_json jsonb NOT NULL DEFAULT '[]'::jsonb,detected_at timestamptz NOT NULL DEFAULT now(),resolved_at timestamptz,resolution_notes text);
CREATE INDEX IF NOT EXISTS idx_shipping_quote_items_carrier_service ON arb.shipping_quote_items(carrier_code,service_code,quoted_at DESC);
CREATE INDEX IF NOT EXISTS idx_shipping_model_metrics_lookup ON arb.shipping_model_metrics(model_version,metric_name,metric_date DESC);
CREATE INDEX IF NOT EXISTS idx_shipping_drift_open ON arb.shipping_model_drift_events(drift_status,detected_at DESC) WHERE resolved_at IS NULL;
INSERT INTO arb.feature_flags(flag_key,is_enabled,description) VALUES('shipping_intelligence_v3_package_optimization',false,'Enable package and DIM optimization'),('shipping_intelligence_v3_digital_twins',false,'Enable SKU shipping digital twins'),('shipping_intelligence_v3_policy_simulation',false,'Enable historical policy replay'),('shipping_intelligence_v3_drift_monitoring',false,'Enable prediction drift monitoring'),('shipping_intelligence_v3_weather',false,'Enable weather risk inputs') ON CONFLICT(flag_key) DO NOTHING;
COMMIT;
